import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import { AuthProvider } from './context/AuthContext';
import { ThemeProvider } from './context/ThemeContext';
import { ToastProvider } from './context/ToastContext';
/* 🎯 MATCH THIS NAME TO THE FILENAME CREATED ABOVE */
import { LivePulseProvider } from './components/LivePulseContext';
import './index.css';

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <AuthProvider>
      <ThemeProvider>
        <ToastProvider>
          {/* 🛰️ Nesting the Pulse Provider inside Toast/Theme */}
          <LivePulseProvider>
            <App />
          </LivePulseProvider>
        </ToastProvider>
      </ThemeProvider>
    </AuthProvider>
  </React.StrictMode>
);
